\section*{Limitations}


\section{Introduction}
Object detection has advanced significantly \cite{smith2024deep}.
Our detector achieves a mAP of 53.3 on COCO \cite{jones2023bert}.

\section{Results}
\begin{table}[h]
\caption{Object detection results on COCO}
\label{tab:coco}
\begin{tabular}{lcc}
\toprule
Method & mAP & AP50 \\
\midrule
YOLO & 45.2 & 63.4 \\
DETR & 50.1 & 68.7 \\
Ours & 54.3 & 72.1 \\
